module div_16bit(
    input clk,
    input rst,
    input sign,
    input [7:0] dividend,
    input [7:0] divisor,
    input opn_valid,
    input res_ready,
    output reg res_valid,
    output [15:0] result
);

reg [15:0] shift_reg;
reg [7:0] divisor_neg;
reg [3:0] counter;
reg [7:0] alu_a, alu_b;
reg alu_cin;
reg [7:0] alu_result;
reg [15:0] final_result;

always @(posedge clk or negedge rst) begin
    if (!rst) begin
        shift_reg <= 16'b0;
        divisor_neg <= 8'b0;
        counter <= 4'b0;
        alu_a <= 8'b0;
        alu_b <= 8'b0;
        alu_cin <= 1'b0;
        alu_result <= 8'b0;
        final_result <= 16'b0;
        res_valid <= 1'b0;
    end else if (opn_valid && !res_valid) begin
        alu_a <= dividend;
        alu_b <= divisor;
        divisor_neg <= ~divisor + 1'b1;
        shift_reg <= {1'b0, dividend, 7'b0};
        counter <= 4'b1;
        res_valid <= 1'b0;
    end else if (!res_valid) begin
        if (counter[3]) begin
            shift_reg <= {shift_reg[14:0], 1'b0};
            if (shift_reg[15:8] >= divisor) begin
                shift_reg[15:8] <= shift_reg[15:8] - divisor;
                shift_reg[0] <= 1'b1;
            end else begin
                shift_reg[0] <= 1'b0;
            end
            counter <= 4'b0;
            final_result <= shift_reg;
            res_valid <= 1'b1;
        end else begin
            counter <= counter + 1'b1;
            alu_result <= alu_a - alu_b - alu_cin;
            alu_cin <= alu_cout;
            alu_a <= alu_result;
            shift_reg <= {shift_reg[14:0], alu_result[7]};
        end
    end else if (res_valid && res_ready) begin
        res_valid <= 1'b0;
    end
end

assign result = final_result;

endmodule
